# Geometry module with shapes

# Regular class with virtual methods (not abstract)
class Shape:
    name: str

    def __init__(self, name: str):
        self.name = name

    def get_description(self) -> str:
        return f"Shape named {self.name}"

    @virtual
    def draw(self) -> str:
        return f"Drawing {self.name}"

    @virtual
    def calculate_area(self) -> float:
        return 0.0

    @virtual
    def scale(self, factor: float) -> str:
        return f"Scaling {self.name} by {factor}"

class Circle(Shape):
    radius: float

    def __init__(self, name: str, radius: float):
        super().__init__(name)
        self.radius = radius

    @override
    def draw(self) -> str:
        return f"Circle({self.name}): r={self.radius}"

    @override
    def get_description(self) -> str:
        return f"A circle named {self.name}"

    @override
    def calculate_area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def scale(self, factor: float) -> str:
        return f"Scaling circle {self.name} by {factor}"

class Rectangle(Shape):
    width: float
    height: float

    def __init__(self, name: str, width: float, height: float):
        super().__init__(name)
        self.width = width
        self.height = height

    @override
    def draw(self) -> str:
        return f"Rectangle({self.name}): {self.width}x{self.height}"

    @override
    def get_description(self) -> str:
        return f"A rectangle named {self.name}"

    @override
    def calculate_area(self) -> float:
        return self.width * self.height

struct Point:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

    def distance_to_origin(self) -> float:
        return (self.x ** 2.0 + self.y ** 2.0) ** 0.5

enum Color:
    RED = 0
    GREEN = 1
    BLUE = 2
    YELLOW = 3

def calculate_total(shapes: list[Shape]) -> float:
    total: float = 0.0
    for s in shapes:
        total += s.calculate_area()
    return total

def create_origin() -> Point:
    return Point(0.0, 0.0)

def color_name(c: Color) -> str:
    return c.name

